9	async function getFixtureIds(
10		request: import('@playwright/test').APIRequestContext
11	): Promise<{ nodeId: string; projectId: string; nodeName: string; projectName: string; projectPath: string }> {
12		const nodeResp = await request.post('/graphql', {
13			data: { query: '{ nodeInfo { id name } }' }
14		});
15		const nodeBody = (await nodeResp.json()) as {
16			data: { nodeInfo: { id: string; name: string } };
17		};
18		const projectsResp = await request.get('/api/projects');
19		const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
20		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
21		if (!fixture) {
22			throw new Error(
23				`fixture server has no ddx-e2e-* project registered (got: ${projects
24					.map((p) => p.id)
25					.join(', ')})`
26			);
27		}
28		return {
29			nodeId: nodeBody.data.nodeInfo.id,
30			projectId: fixture.id,
31			nodeName: nodeBody.data.nodeInfo.name,
32			projectName: fixture.name,
33			projectPath: fixture.path
34		};
35	}
