117	function makeWorkersResponse(
118		workers: Record<string, unknown>[] = WORKERS,
119		maxCount: number | null = null
120	) {
121		return {
122			workersByProject: {
123				edges: workers.map((w, i) => ({ node: w, cursor: `cursor-${i}` })),
124				pageInfo: { hasNextPage: false, endCursor: null },
125				totalCount: workers.length
126			},
127			queueAndWorkersSummary: { maxCount }
128		};
129	}
130	
131	function makeSessionsResponse(sessions: Record<string, unknown>[] = []) {
132		return {
133			agentSessions: {
134				edges: sessions.map((node) => ({ node, cursor: String(node.id) })),
135				pageInfo: { hasNextPage: false, endCursor: null },
136				totalCount: sessions.length
137			},
138			// SessionsPage's loader requests both connections in one query and
139			// dereferences `sessionsCostSummary.localSessionCount` immediately —
140			// returning null here would crash the page render.
141			sessionsCostSummary: {
142				cashUsd: 0,
143				subscriptionEquivUsd: 0,
144				localSessionCount: 0,
145				localEstimatedUsd: 0
146			}
147		};
148	}
