150	/**
151	 * Set up GraphQL route mocking for the workers pages.
152	 */
153	async function mockGraphQL(
154		page: import('@playwright/test').Page,
155		workers = WORKERS,
156		reportedWorkers: Record<string, unknown>[] = []
157	) {
158		await page.route('/graphql', async (route) => {
159			const body = route.request().postDataJSON() as { query: string };
160	
161			if (body.query.includes('NodeInfo')) {
162				await route.fulfill({
163					status: 200,
164					contentType: 'application/json',
165					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
166				});
167			} else if (body.query.includes('Projects')) {
168				await route.fulfill({
169					status: 200,
170					contentType: 'application/json',
171					body: JSON.stringify({
172						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
173					})
174				});
175			} else if (body.query.includes('ReportedWorkersByProject') || body.query.includes('reportedWorkers')) {
176				await route.fulfill({
177					status: 200,
178					contentType: 'application/json',
179					body: JSON.stringify({ data: { reportedWorkers } })
180				});
181			} else if (body.query.includes('WorkersByProject')) {
182				await route.fulfill({
183					status: 200,
184					contentType: 'application/json',
185					body: JSON.stringify({ data: makeWorkersResponse(workers) })
186				});
187			} else if (body.query.includes('WorkerDetail')) {
188				await route.fulfill({
189					status: 200,
190					contentType: 'application/json',
191					body: JSON.stringify({ data: { worker: WORKER_DETAIL } })
192				});
193			} else if (body.query.includes('WorkerLog')) {
194				await route.fulfill({
195					status: 200,
196					contentType: 'application/json',
197					body: JSON.stringify({ data: { workerLog: WORKER_LOG } })
198				});
199			} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
200				await route.fulfill({
201					status: 200,
202					contentType: 'application/json',
203					body: JSON.stringify({ data: makeSessionsResponse() })
204				});
205			} else if (body.query.includes('WorkerProgress')) {
206				// Subscriptions are handled over WebSocket; pass through
207				await route.continue();
208			} else {
209				await route.continue();
210			}
211		});
212	}
