		currentBead: 'bead-alpha-001',
		attempts: 3,
		successes: 2,
		failures: 1,
		startedAt: '2026-06-01T10:00:00Z',
		projectId: PROJECT_ALPHA.id,
		projectName: PROJECT_ALPHA.name
	},
	{
		id: 'worker-bbbbbbbb',
		kind: 'work',
		state: 'idle',
		status: null,
		harness: 'claude',
		model: 'claude-sonnet-4-6',
		currentBead: null,
		attempts: 5,
		successes: 5,
		failures: 0,
		startedAt: '2026-06-01T09:00:00Z',
