		projectName: PROJECT_BETA.name
	}
];

// Worker detail fixture for the running worker.
const WORKER_DETAIL_ALPHA = {
	id: 'worker-aaaaaaaa',
	kind: 'execute-bead',
	state: 'running',
	status: 'processing',
	harness: 'claude',
	model: 'claude-sonnet-4-6',
