					}
				})
			});
		} else if (body.query.includes('WorkerDetail') || body.query.includes('worker(') || body.query.includes('Worker(')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						worker: {
							id: WORKER_ID,
							kind: 'work',
							state: workerState,
							status: workerState,
							harness: 'claude',
